export interface membersLogicValues {
    members: unknown[];
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface membersLogicActions {
    ensureAllMembersLoaded: () => {
        value: true;
    };
}

export type membersLogicType = MakeLogicType<membersLogicValues, membersLogicActions>;

// Toolbar shim — prevents the real membersLogic from auto-mounting and making API requests to the wrong host
